(function(){
  function escapeHtml(value){
    return String(value)
      .replace(/&/g,'&amp;')
      .replace(/</g,'&lt;')
      .replace(/>/g,'&gt;')
      .replace(/"/g,'&quot;')
      .replace(/'/g,'&#39;');
  }
  window.hljs = window.hljs || {
    highlight: function(value){ return { value: escapeHtml(value) }; },
    highlightElement: function(){},
  };
})();
